// ─── Card Component ───────────────────────────────────────────────────────────

function HoverCard({ card }: { card: CardData }) {
  const cardRef = useRef<HTMLDivElement>(null);
  const tlRef = useRef<gsap.core.Timeline | null>(null);

  useEffect(() => {
    const el = cardRef.current;
    if (!el) return;

    const paths = el.querySelectorAll<SVGPathElement>('.svg-stroke path');
    const wordInners = el.querySelectorAll<HTMLSpanElement>('.word-inner');

    paths.forEach((path) => {
      const len = path.getTotalLength();
      path.style.strokeDasharray = String(len);
      path.style.strokeDashoffset = String(len);
    });

    gsap.set(wordInners, { yPercent: 100 });

    const onEnter = () => {
      if (tlRef.current) tlRef.current.kill();
      const tl = gsap.timeline();
      tlRef.current = tl;

      paths.forEach((path) => {
        tl.to(
          path,
          {
            strokeDashoffset: 0,
            strokeWidth: 70,
            duration: 1.5,
            ease: 'power2.inOut',
          },
          0,
        );
      });
      tl.to(
        wordInners,
        { yPercent: 0, duration: 0.75, ease: 'power3.out', stagger: 0.075 },
        0.35,
      );
    };

    const onLeave = () => {
      if (tlRef.current) tlRef.current.kill();
      const tl = gsap.timeline();
      tlRef.current = tl;

      paths.forEach((path) => {
        const len = path.getTotalLength();
        tl.to(
          path,
          {
            strokeDashoffset: len,
            strokeWidth: 2,
            duration: 1,
            ease: 'power2.out',
          },
          0,
        );
      });
      tl.to(
        wordInners,
        {
          yPercent: 100,
          duration: 0.5,
          ease: 'power3.out',
          stagger: { each: 0.05, from: 'end' },
        },
        0,
      );
    };

    el.addEventListener('mouseenter', onEnter);
    el.addEventListener('mouseleave', onLeave);

    return () => {
      el.removeEventListener('mouseenter', onEnter);
      el.removeEventListener('mouseleave', onLeave);
      if (tlRef.current) tlRef.current.kill();
    };
  }, []);

  return (
    <div
      ref={cardRef}
      id={card.id}
      className='relative w-full rounded-2xl overflow-hidden cursor-pointer'
      style={{ aspectRatio: '1 / 1' }}
    >
      {/* Image */}
      <img
        src={card.imageSrc}
        alt={card.titleLine1}
        className='absolute inset-0 w-full h-full object-cover'
      />

      {/* Coloured SVG stroke (swirl) */}
      <div
        className='svg-stroke absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 scale-150 w-full h-full pointer-events-none'
        style={{ '--stroke-color': card.strokeColor } as React.CSSProperties}
      >
        <svg
          xmlns='http://www.w3.org/2000/svg'
          viewBox='0 0 375 259'
          className='w-full h-full'
        >
          <g transform='translate(346 215.99999999999994) rotate(0 -158.5 -86.49999999999994)'>
            <path
              d={SWIRL_PATH}
              fill='none'
              stroke={card.strokeColor}
              strokeWidth={2}
            />
          </g>
        </svg>
      </div>

      {/* Grey SVG stroke (spiral) */}
      <div className='svg-stroke absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 scale-150 w-full h-full pointer-events-none'>
        <svg
          xmlns='http://www.w3.org/2000/svg'
          viewBox='0 0 330 301'
          className='w-full h-full'
        >
          <g transform='translate(177 289) rotate(0 -12 -138.5)'>
            <path
              d={SPIRAL_PATH}
              fill='none'
              stroke='#e0e0e0'
              strokeWidth={2}
            />
          </g>
        </svg>
      </div>

      {/* Title */}
      <div className='absolute bottom-8 left-8 text-black max-md:bottom-4 max-md:left-4'>
        <h3
          className='font-medium leading-tight tracking-tight'
          style={{
            fontSize: 'clamp(1.5rem, 2.5vw, 3rem)',
            letterSpacing: '-0.025rem',
          }}
        >
          <span className='overflow-hidden inline-block'>
            <span className='word-inner inline-block'>{card.titleLine1}</span>
          </span>{' '}
          <span className='overflow-hidden inline-block'>
            <span className='word-inner inline-block'>{card.titleLine2}</span>
          </span>
        </h3>
      </div>
    </div>
  );
}

